#include <stddef.h>

/* Hex codec maintained by the persona. Hosted C, not freestanding. */

static int nibble(char c) {
  if (c >= '0' && c <= '9') return c - '0';
  if (c >= 'a' && c <= 'f') return c - 'a' + 10;
  if (c >= 'A' && c <= 'F') return c - 'A' + 10;
  return -1;
}

size_t hex_encode(const unsigned char *in, size_t in_len, char *out) {
  static const char digits[] = "0123456789abcdef";
  size_t i;
  for (i = 0; i < in_len; i++) {
    out[2 * i] = digits[in[i] >> 4];
    out[2 * i + 1] = digits[in[i] & 0x0f];
  }
  return 2 * in_len;
}

/* Returns decoded length, or 0 on invalid input (odd length or bad digit). */
size_t hex_decode(const char *in, size_t in_len, unsigned char *out) {
  size_t i;
  if (in_len % 2 != 0) return 0;
  for (i = 0; i < in_len; i += 2) {
    int hi = nibble(in[i]);
    int lo = nibble(in[i + 1]);
    if (hi < 0 || lo < 0) return 0;
    out[i / 2] = (unsigned char)((hi << 4) | lo);
  }
  return in_len / 2;
}

/* G24 metamorphic specimen. Freestanding x86_64 Linux ELF, no libc.
 * Reads argv[1] as an unsigned 32-bit value; prints bswap32(x) in decimal.
 * The relation f(f(x))==x (involution) is the oracle; no expected value is
 * computed by the verifier. Linux x86_64 ABI: argc at [rsp], argv[i] at
 * rsp+8+i*8. Minted once in a pinned container; CI runs the committed image. */

static long sys_write(long fd, const void *buf, long n) {
  long ret;
  __asm__ volatile("syscall"
                   : "=a"(ret)
                   : "a"(1L), "D"(fd), "S"(buf), "d"(n)
                   : "rcx", "r11", "memory");
  return ret;
}

static void sys_exit(long code) __attribute__((noreturn));
static void sys_exit(long code) {
  __asm__ volatile("syscall" : : "a"(60L), "D"(code) : "rcx", "r11", "memory");
  __builtin_unreachable();
}

static unsigned long parse_u(const char *s) {
  unsigned long n = 0;
  while (*s >= '0' && *s <= '9') {
    n = n * 10UL + (unsigned long)(*s - '0');
    s++;
  }
  return n;
}

static void print_u(unsigned long n) {
  char buf[32];
  int i = 0;
  if (n == 0) {
    buf[i++] = '0';
  } else {
    char tmp[32];
    int j = 0;
    while (n > 0) {
      tmp[j++] = (char)('0' + (n % 10UL));
      n /= 10UL;
    }
    while (j > 0)
      buf[i++] = tmp[--j];
  }
  buf[i++] = '\n';
  sys_write(1, buf, i);
}

#if defined(EVIL_BSWAP)
/* Rotate-by-8 misread for a byte swap. f(f(x)) is rotate-by-16, not the
 * identity, so the involution relation rejects it on any value whose low and
 * high halfwords differ. */
static unsigned long bswap32(unsigned long x) {
  unsigned long v = x & 0xFFFFFFFFUL;
  return ((v << 8) | (v >> 24)) & 0xFFFFFFFFUL;
}
#elif defined(IMPOSTER_BSWAP)
/* Swaps only the outer byte pair; leaves the inner pair. This IS an involution
 * (applying it twice restores the input) but it is NOT a byte swap. The
 * involution relation accepts it: the documented ceiling. Only a value oracle
 * separates it from the real bswap32. */
static unsigned long bswap32(unsigned long x) {
  unsigned long v = x & 0xFFFFFFFFUL;
  return ((v & 0x000000FFUL) << 24) | (v & 0x0000FF00UL) | (v & 0x00FF0000UL) |
         ((v & 0xFF000000UL) >> 24);
}
#else
static unsigned long bswap32(unsigned long x) {
  unsigned long v = x & 0xFFFFFFFFUL;
  return ((v & 0x000000FFUL) << 24) | ((v & 0x0000FF00UL) << 8) |
         ((v & 0x00FF0000UL) >> 8) | ((v & 0xFF000000UL) >> 24);
}
#endif

__attribute__((noreturn))
void real_start(long argc, const char *arg1) {
  if (argc < 2)
    sys_exit(1);
  print_u(bswap32(parse_u(arg1)));
  sys_exit(0);
}

__attribute__((naked))
void _start(void) {
  __asm__("mov (%rsp), %rdi\n"
          "mov 16(%rsp), %rsi\n"
          "call real_start\n");
}

#!/usr/bin/env bash
set -euo pipefail
ROOT="$(cd "$(dirname "$0")/.." && pwd)"
cd "$ROOT"

usage() {
  cat <<'EOF'
usage: nanograph <command> [args...]

Commands:
  doctor
      Validate runner + core binaries on this host.

  demo utf8
      Run the ICP UTF-8 demo.

  fit <case.fit>
      Score a candidate with the case-fit rubric.

  verify [--expect accept|reject] <candidate.ngb> <request.req>
      Run metamorphic verification. Prints the verifier output line.
      Without --expect, exits with verifier exit code (accept=0, reject=1).
      With --expect, exits 0 only if verdict matches expected.

  mint c <src.c> <out.ngb>
  mint rust <src.rs> <out.ngb> [--cfg name...]
  mint go <src.go> <out.ngb> [--tags tag,...]
  mint zig <srcdir> <src.zig> <out.ngb>
      Mint a language specimen into .ngb via existing minter scripts.

  help
      Print this message.
EOF
}

require_runner() {
  if ! ./scripts/check-linux-runner.sh --quiet; then
    echo "nanograph doctor: no Linux ELF runner (native Linux, qemu-x86_64, or Docker)." >&2
    exit 1
  fi
}

cmd_doctor() {
  require_runner
  make -C tools -s bin/ngb-pack bin/ngb-parse bin/ngb-extract >/dev/null
  echo "nanograph doctor OK"
}

cmd_demo() {
  local name="${1:-}"
  case "$name" in
    utf8) ./scripts/demo-utf8.sh ;;
    *) echo "nanograph demo: expected 'utf8'" >&2; exit 2 ;;
  esac
}

cmd_fit() {
  local file="${1:-}"
  [[ -n "$file" ]] || { echo "nanograph fit: missing <case.fit>" >&2; exit 2; }
  ./scripts/score-case-fit.sh "$file"
}

cmd_verify() {
  local expected=""
  if [[ "${1:-}" == "--expect" ]]; then
    expected="${2:-}"
    [[ "$expected" == "accept" || "$expected" == "reject" ]] || {
      echo "nanograph verify: --expect must be accept|reject" >&2
      exit 2
    }
    shift 2
  fi

  local cand="${1:-}" req="${2:-}"
  [[ -n "$cand" && -n "$req" ]] || {
    echo "nanograph verify: usage verify [--expect accept|reject] <candidate.ngb> <request.req>" >&2
    exit 2
  }

  set +e
  local output rc verdict
  output="$(./scripts/agent-eval/metamorphic-verify.sh "$cand" "$req" 2>&1)"
  rc=$?
  set -e
  printf '%s\n' "$output"
  verdict="$(printf '%s\n' "$output" | sed -n 's/^verdict=\([^ ]*\).*/\1/p' | tail -1)"

  if [[ -z "$expected" ]]; then
    exit "$rc"
  fi

  [[ "$verdict" == "$expected" ]] || {
    echo "nanograph verify: expected $expected got ${verdict:-unknown}" >&2
    exit 1
  }
}

cmd_mint() {
  local lang="${1:-}"
  shift || true
  case "$lang" in
    c) ./scripts/mint-one-elf.sh "$@" ;;
    rust) ./scripts/mint-one-rust.sh "$@" ;;
    go) ./scripts/mint-one-go.sh "$@" ;;
    zig) ./scripts/mint-one-zig.sh "$@" ;;
    *) echo "nanograph mint: expected one of c|rust|go|zig" >&2; exit 2 ;;
  esac
}

cmd="${1:-help}"
shift || true
case "$cmd" in
  doctor) cmd_doctor "$@" ;;
  demo) cmd_demo "$@" ;;
  fit) cmd_fit "$@" ;;
  verify) cmd_verify "$@" ;;
  mint) cmd_mint "$@" ;;
  help|-h|--help) usage ;;
  *) echo "nanograph: unknown command '$cmd'" >&2; usage; exit 2 ;;
esac
